/**
 * Fork from https://github.com/popperjs/popper-core/blob/4800b37c5b4cabb711ac1d904664a70271487c4b/src/dom-utils/getWindow.js
 */

function isWindow(node: Node | typeof window): node is typeof window {
  return node.toString() === '[object Window]';
}

export default function getWindow(node: Node | typeof window | null): typeof window {
  if (!node) {
    return window;
  }

  if (!isWindow(node)) {
    const { ownerDocument } = node;
    return ownerDocument ? ownerDocument.defaultView || window : window;
  }

  return node;
}
